-- Migration: deepl_en
-- Generated: 2026-06-01 19:39:22
-- Words count: 31
-- Language: en
-- Strategy: UPSERT (insert or update existing, preserve existing IDs)

BEGIN;
SELECT pg_advisory_lock(hashtext('data_migrations_global_lock'));
SET LOCAL statement_timeout = '10min';
SET LOCAL lock_timeout = '60s';
SET LOCAL client_min_messages = warning;

-- Ensure languages exist (idempotent)
ON CONFLICT ("code") DO NOTHING;

-- Ensure part of speech exists
ON CONFLICT ("name") DO NOTHING;

-- Ensure word sources exist (including migration label)
ON CONFLICT ("code") DO NOTHING;

-- UPSERT BaseWord records
-- New words get sourceId = dm_...; existing words keep their sourceId (so rollback does not delete them)
ON CONFLICT ("word", "languageId") DO NOTHING;

-- UPSERT WordTranslation records (subquery resolves baseWordId)
ON CONFLICT ("baseWordId", "languageId", "priority") DO UPDATE SET
  "translation" = EXCLUDED."translation",
  "partOfSpeechId" = EXCLUDED."partOfSpeechId";

-- Replace examples: delete old rows and insert new ones.
-- Tag new examples with sourceId = dm_... (for selective rollback deletion)
DELETE FROM "WordExample"
WHERE "baseWordId" IN (
  SELECT "id" FROM "BaseWord"
  WHERE "word" IN ('accusing', 'broom', 'chopsticks', 'cipher', 'congestion', 'content acquisition', 'crawl', 'crowd', 'decomposing', 'deliberate', 'deputy', 'duro', 'farther', 'finest', 'further', 'gauge', 'get axed', 'heap', 'impose', 'instance', 'intent', 'napkin', 'pile', 'reliably', 'retention', 'rifle', 'secrecy', 'sentinel', 'summary', 'take on', 'unforeseen circumstances')
  AND "languageId" = (SELECT "id" FROM "Language" WHERE "code" = 'en')
);

